// ─── Parse and validate the generation request ───────────────
const body = $json.body || $json;

const business_id = body.business_id;
const business_name = body.business_name || 'Business';
const business_category = body.business_category || 'general';
const user_prompt = body.user_prompt || body.prompt || '';
const custom_description = body.custom_description || '';
const llama_endpoint = body.llama_endpoint || 'http://localhost:11434';
const model = body.model || 'llama3';
const refinement_mode = body.refinement_mode || false;
const existing_workflow = body.existing_workflow || null;

if (!user_prompt) {
  throw new Error('VALIDATION: user_prompt is required for workflow generation.');
}

return [{
  json: {
    business_id,
    business_name,
    business_category,
    user_prompt,
    custom_description,
    llama_endpoint,
    model,
    refinement_mode,
    existing_workflow
  }
}];

// ─── STEP 1: Intent Extraction Prompt ────────────────────────────────────
// Light-weight pre-pass: extract structured intent from the user's natural language request.
// This reduces hallucination and improves Llama's graph structure accuracy.
const req = $node['Parse Generation Request'].json;

const intent_prompt = `Analyze this business workflow request and extract configuration parameters as JSON.
Output ONLY a valid JSON object with exactly these keys. No explanation, no markdown.

{
  "business_type": "string (restaurant|salon|clinic|gym|ecommerce|education|support|delivery|finance|custom)",
  "needs_payment": boolean,
  "needs_delivery": boolean,
  "needs_appointment": boolean,
  "needs_catalog": boolean,
  "needs_support_escalation": boolean,
  "needs_subscription": boolean,
  "preferred_terminology": {
    "order_noun": "string (Order|Booking|Appointment|Membership|Subscription)",
    "catalog_noun": "string (Menu|Services|Products|Courses|Plans)",
    "staff_noun": "string (Staff|Stylist|Doctor|Trainer|Agent)"
  }
}

Business Category: ${req.business_category}
User Request: "${req.user_prompt}"
Custom Description: "${req.custom_description || 'none'}"

JSON:`;

return [{
  json: {
    ...req,
    intent_prompt
  }
}];

// ─── Parse Llama intent response + local fallback heuristics ───────────
const req = $node['Parse Generation Request'].json;
const llamaResponse = $json;
const promptLower = req.user_prompt.toLowerCase();
const catLower = req.business_category.toLowerCase();

// Local fallback intent — always computed in case Llama is offline
const fallback_intent = {
  business_type: catLower.includes('salon') || catLower.includes('spa') ? 'salon'
               : catLower.includes('clinic') || catLower.includes('hospital') ? 'clinic'
               : catLower.includes('gym') || catLower.includes('fitness') ? 'gym'
               : catLower.includes('restaurant') || catLower.includes('food') || catLower.includes('cafe') ? 'restaurant'
               : catLower.includes('ecommerce') || catLower.includes('store') || catLower.includes('shop') ? 'ecommerce'
               : catLower.includes('education') || catLower.includes('school') ? 'education'
               : 'custom',
  needs_payment: promptLower.includes('pay') || promptLower.includes('stripe') || promptLower.includes('checkout') || promptLower.includes('cash'),
  needs_delivery: promptLower.includes('deliver') || promptLower.includes('ship') || promptLower.includes('courier') || promptLower.includes('address'),
  needs_appointment: promptLower.includes('book') || promptLower.includes('appointment') || promptLower.includes('slot') || promptLower.includes('schedul'),
  needs_catalog: true,
  needs_support_escalation: promptLower.includes('escalat') || promptLower.includes('support') || promptLower.includes('agent') || promptLower.includes('human'),
  needs_subscription: promptLower.includes('subscript') || promptLower.includes('member') || promptLower.includes('renew'),
  preferred_terminology: {
    order_noun: catLower.includes('salon') ? 'Booking' : catLower.includes('clinic') ? 'Appointment' : catLower.includes('gym') ? 'Membership' : 'Order',
    catalog_noun: catLower.includes('salon') ? 'Services' : catLower.includes('clinic') ? 'Consultations' : catLower.includes('gym') ? 'Plans' : catLower.includes('restaurant') ? 'Menu' : 'Products',
    staff_noun: catLower.includes('salon') ? 'Stylist' : catLower.includes('clinic') ? 'Doctor' : catLower.includes('gym') ? 'Trainer' : 'Staff'
  }
};

// Try to parse Llama's JSON response
let intent = fallback_intent;
try {
  const raw = llamaResponse?.response || '';
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}') + 1;
  if (start !== -1 && end > start) {
    const parsed = JSON.parse(raw.substring(start, end));
    intent = { ...fallback_intent, ...parsed };
  }
} catch (e) {
  // Llama offline or returned non-JSON — use fallback
  console.log('Intent fallback: Llama unavailable or returned non-JSON');
}

// Get runtime context and business data
const runtime_context = $node['Fetch FlowCore Runtime Context'].json?.data || '';
const business_data = $node['Fetch Business Metadata'].json?.data || {};
const catalog_raw = business_data.catalog_json || '{}';
const catalog = (() => { try { return JSON.parse(catalog_raw); } catch { return {}; } })();

return [{
  json: {
    ...req,
    intent,
    runtime_context,
    business_name: business_data.name || req.business_name,
    catalog,
    using_fallback: intent === fallback_intent
  }
}];

// ─── STEP 2: Build Full Workflow Generation Prompt ───────────────────────
// Combines: FlowCore runtime context + business metadata + extracted intent
// This is the main prompt that produces the complete workflow graph JSON.
const ctx = $json;
const { intent, business_name, business_category, user_prompt, custom_description, runtime_context, catalog, refinement_mode, existing_workflow } = ctx;

const terminology = intent.preferred_terminology;

// Build intent annotation
const intent_summary = `
EXTRACTED WORKFLOW INTENT:
- Business Type: ${intent.business_type}
- ${terminology.order_noun} Management: Yes
- Payment Integration: ${intent.needs_payment ? 'YES (include create_payment + confirm_payment nodes)' : 'NO'}
- Delivery/Shipping: ${intent.needs_delivery ? 'YES (include collect_address + create_delivery nodes)' : 'NO'}
- ${terminology.order_noun} Booking System: ${intent.needs_appointment ? 'YES (slot-based collection flow)' : 'NO'}
- Support Escalation: ${intent.needs_support_escalation ? 'YES (include notify_customer escalation node)' : 'NO'}
- ${terminology.catalog_noun}: ${JSON.stringify(Object.keys(catalog).length > 0 ? catalog : { note: 'Use generic examples based on business type' })}

BUSINESS-SPECIFIC TERMINOLOGY:
- Refer to orders as: "${terminology.order_noun}"
- Refer to catalog as: "${terminology.catalog_noun}"
- Refer to staff as: "${terminology.staff_noun}"
`;

// Build refinement instruction if in refinement mode
const refinement_section = refinement_mode && existing_workflow
  ? `\nREFINEMENT MODE: You are modifying an existing workflow. Here is the current workflow:\n${JSON.stringify(existing_workflow, null, 2)}\n\nApply the following changes: "${user_prompt}"\nKeep all existing valid nodes and edges. Only add/modify what the change request requires.\n`
  : '';

// Build dynamic operational actions section
const actions_section = `
OPERATIONAL ACTIONS TO INCLUDE IN WORKFLOW:
For each major FSM state, the workflow should support these operational actions via user input:
- CART state: User can send 'VIEW_CART', 'CLEAR_CART'
- CHECKOUT state: User can send 'VIEW_CART', 'CANCEL_ORDER'
- PAYMENT state: User can send 'RETRY_PAYMENT', 'CANCEL_ORDER'
- CONFIRMED state: User can send 'TRACK_DELIVERY', 'REORDER', 'CONTACT_SUPPORT'

For ${intent.business_type} specifically:
${intent.business_type === 'salon' ? '- Include RESCHEDULE_BOOKING and CANCEL_BOOKING actions in CONFIRMED state' : ''}
${intent.business_type === 'clinic' ? '- Include VIEW_PRESCRIPTION and CONTACT_RECEPTION actions in CONFIRMED state' : ''}
${intent.business_type === 'gym' ? '- Include VIEW_MEMBERSHIP, RENEW_PLAN, BOOK_TRAINER actions' : ''}
${intent.business_type === 'ecommerce' ? '- Include TRACK_SHIPMENT, RETURN_PRODUCT actions in CONFIRMED state' : ''}
`;

const full_prompt = `${runtime_context}\n\n---\n\n${intent_summary}\n\n${refinement_section}\n${actions_section}\n\n==================================================\nGENERATION TASK\n==================================================\n\nBusiness Name: ${business_name}\nBusiness Category: ${business_category}\nUser Request: "${user_prompt}"\n${custom_description ? `Additional Context: "${custom_description}"` : ''}\n\nGenerate a complete, valid FlowCore workflow graph JSON for this specific business.\n\nCRITICAL REQUIREMENTS:\n1. Output ONLY the raw JSON object — no markdown, no explanation, no backticks.\n2. The workflow must be tailored to ${business_name} (a ${business_category} business).\n3. All node module_names must be from the VALID MODULE LIST in the context above.\n4. The fsm_transition_table must map every transition actually used by nodes.\n5. No cycles in edges unless explicitly conditional with input_equals conditions.\n6. Every terminal path must end in CONFIRMED or CANCELLED state.\n7. business_id must be: "${ctx.business_id || 'temp_biz_id'}"\n8. Use business-specific welcome messages, terminology, and product/service names.\n9. For payment: use create_payment + confirm_payment nodes in sequence.\n10. For delivery: use collect_address BEFORE create_delivery.\n\nJSON Output:`;

return [{
  json: {
    ...ctx,
    full_prompt
  }
}];

// ─── Parse Llama's generated workflow JSON ──────────────────────────────
const ctx = $node['Build Full Generation Prompt'].json;
const llamaResponse = $json;

let workflow_graph = null;
let using_mock = false;

try {
  const raw = llamaResponse?.response || '';
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}') + 1;
  if (start !== -1 && end > start) {
    workflow_graph = JSON.parse(raw.substring(start, end));
  }
} catch (e) {
  console.log('Llama output parse failed:', e.message);
}

// ─── Mock Synthesis Fallback ──────────────────────────────────────────
// Used when Llama is offline or returns invalid JSON.
// Generates a semantically correct FlowCore graph based on extracted intent.
if (!workflow_graph) {
  using_mock = true;
  const intent = ctx.intent;
  const biz_name = ctx.business_name;
  const biz_id = ctx.business_id || 'temp_biz_id';
  const t = intent.preferred_terminology;

  const nodes = {
    node_welcome: {
      id: 'node_welcome',
      module_name: 'show_menu',
      config: {
        menu_header: `Welcome to ${biz_name}!\n\nHere are our ${t.catalog_noun.toLowerCase()}:\n1. Option A\n2. Option B\n3. Option C\n\nReply with your selection.`
      },
      fsm_transition_to: 'MENU'
    },
    node_collect: {
      id: 'node_collect',
      module_name: 'collect_cart',
      config: { expects_user_input: true },
      fsm_transition_to: 'CART'
    },
    node_total: {
      id: 'node_total',
      module_name: 'calculate_total',
      config: {},
      fsm_transition_to: 'CHECKOUT'
    }
  };

  const edges = [
    { from_node: 'node_welcome', to_node: 'node_collect', condition: { type: 'any_input', value: '' } },
    { from_node: 'node_collect', to_node: 'node_total', condition: { type: 'always', value: '' } }
  ];

  const fsm_table = {
    START: { MENU: 'show_menu' },
    MENU: { CART: 'collect_cart' },
    CART: { CHECKOUT: 'calculate_total' }
  };

  // Add payment if needed
  if (intent.needs_payment) {
    nodes['node_payment'] = { id: 'node_payment', module_name: 'create_payment', config: { gateway: 'stripe', currency: 'USD' }, fsm_transition_to: 'PAYMENT' };
    nodes['node_confirm_pay'] = { id: 'node_confirm_pay', module_name: 'confirm_payment', config: {}, fsm_transition_to: 'CONFIRMED' };
    edges.push({ from_node: 'node_total', to_node: 'node_payment', condition: { type: 'always', value: '' } });
    edges.push({ from_node: 'node_payment', to_node: 'node_confirm_pay', condition: { type: 'always', value: '' } });
    fsm_table['CHECKOUT'] = { PAYMENT: 'create_payment' };
    fsm_table['PAYMENT'] = { CONFIRMED: 'confirm_payment' };
  }

  // Add delivery if needed
  if (intent.needs_delivery) {
    nodes['node_address'] = { id: 'node_address', module_name: 'collect_address', config: { expects_user_input: true }, fsm_transition_to: 'CONFIRMED' };
    nodes['node_delivery'] = { id: 'node_delivery', module_name: 'create_delivery', config: {}, fsm_transition_to: 'CONFIRMED' };
    const prev_node = intent.needs_payment ? 'node_confirm_pay' : 'node_total';
    edges.push({ from_node: prev_node, to_node: 'node_address', condition: { type: 'always', value: '' } });
    edges.push({ from_node: 'node_address', to_node: 'node_delivery', condition: { type: 'always', value: '' } });
  }

  // Always end with notify
  const last_nodes = intent.needs_delivery ? ['node_delivery'] : intent.needs_payment ? ['node_confirm_pay'] : ['node_total'];
  nodes['node_notify'] = {
    id: 'node_notify',
    module_name: 'notify_customer',
    config: { message: `Your ${t.order_noun.toLowerCase()} with ${biz_name} has been confirmed! Thank you.` },
    fsm_transition_to: 'CONFIRMED'
  };
  last_nodes.forEach(ln => edges.push({ from_node: ln, to_node: 'node_notify', condition: { type: 'always', value: '' } }));
  if (!fsm_table['CONFIRMED']) fsm_table['CONFIRMED'] = {};

  workflow_graph = {
    business_id: biz_id,
    version_number: 1,
    entry_node_id: 'node_welcome',
    nodes,
    edges,
    fsm_transition_table: fsm_table
  };
}

return [{
  json: {
    business_id: ctx.business_id,
    workflow_graph,
    intent: ctx.intent,
    using_mock,
    business_name: ctx.business_name,
    business_category: ctx.business_category
  }
}];
